/**
 * Type guard to check if the value is a primitive number
 * @param  value - a value to be checked
 * @returns return true if it's a number or false if it's not
 **/
export const isNumber = (value: unknown): value is number => {
  return typeof value === 'number';
};

/**
 * Type guard to check if the value is a primitive string
 * @param value - a value to be checked
 * @returns return true if it's a string or false if it's not
 **/
export const isString = (value: unknown): value is string => {
  return typeof value === 'string';
};

/**
 * Type guard to check if the value is a instance of Date object
 * @param value - a value to be checked
 * @returns return true if it's a Date object or false if it's not
 **/
export const isDate = (value: unknown): value is Date => {
  return value instanceof Date;
};

export const isFunction = <T = XYChartData, U = string>(
  fn: unknown,
): fn is (data: T) => U => {
  return typeof fn === 'function';
};

