const REGEX_LINEAR = /linear/;
const REGEX_LOG = /log/;
const REGEX_TIME = /^time$/;
const REGEX_CATEGORICAL = /^categorical$/;
const REGEX_NUMERICAL = /numerical/;
const REGEX_ANY_NUMBER = /^numerical|^time$/;

export const isLinear = (axisType: string) => REGEX_LINEAR.test(axisType);

export const isLogarithmic = (axisType: string) => REGEX_LOG.test(axisType);

export const isTime = (axisType: string) => REGEX_TIME.test(axisType);

export const isCategorical = (axisType: string) =>
  REGEX_CATEGORICAL.test(axisType);

export const isNumerical = (axisType: string) => REGEX_NUMERICAL.test(axisType);

export const isAnyNumber = (axisType: string) =>
  REGEX_ANY_NUMBER.test(axisType);

export function isLinearAxis(
  axis: XYChartAxisInternal,
): axis is XYChartAxisInternal & XYChartLinearAxisInternalProps {
  return isLinear(axis.type);
}

export function isLogarithmicAxis(
  axis: XYChartAxisInternal,
): axis is XYChartAxisInternal & XYChartLogAxisInternalProps {
  return isLogarithmic(axis.type);
}

export function isNumericalAxis(
  axis: XYChartAxisInternal,
): axis is XYChartAxisInternal &
  (XYChartLinearAxisInternalProps | XYChartLogAxisInternalProps) {
  return isNumerical(axis.type);
}

export function isAnyNumericalAxis<
  T extends { type: XYChartAxisInternal['type'] },
>(axis: T): axis is T & { type: XYAxisAnyNumericalType } {
  return !isCategorical(axis.type);
}

export function isTimeAxis(
  axis: XYChartAxisInternal,
): axis is XYChartAxisInternal & XYChartTimeAxisProps {
  return isTime(axis.type);
}

export function isCategoricalAxis(axis: {
  type: XYChartAxisInternal['type'];
}): axis is XYChartAxisInternal & XYChartCategoricalAxisProps {
  return isCategorical(axis.type);
}

export function isCategoricalScale(args: {
  axisType: XYAxisInternalTypes | undefined;
  axisScale: AnyScale | undefined;
}): args is { axisType: CATEGORICAL; axisScale: CategoricalScales } {
  return !!args.axisType && isCategoricalAxis({ type: args.axisType });
}

export function isTimeScale(args: {
  axisType: XYAxisInternalTypes | undefined;
  axisScale: AnyScale | undefined;
}): args is { axisType: TIME; axisScale: DateScales } {
  return !!args.axisType && isTime(args.axisType);
}

export function isAnyNumericalScale(args: {
  axisType: XYAxisInternalTypes | undefined;
  axisScale: AnyScale | undefined;
}): args is { axisType: XYAxisInternalTypes; axisScale: AnyNumberScale } {
  return !!args.axisType && isAnyNumericalAxis({ type: args.axisType });
}

export function isDotContentPoint(
  content: XYChartExploreState['content'],
): content is {
  type: typeof DOT_VARIANT;
  series: DotSeriesWithDatapoints;
  datapoint: DotDatapoint;
} {
  return (
    !!content &&
    content.type === DOT_VARIANT &&
    !!content.series &&
    !!content.datapoint
  );
}

export function isLineContentPoint(
  content: XYChartExploreState['content'],
): content is {
  type: typeof LINE_VARIANT;
  series: LineSeriesWithDatapoints;
  datapoint: LineDatapoint;
} {
  return (
    !!content &&
    content.type === LINE_VARIANT &&
    !!content.series &&
    !!content.datapoint
  );
}

export function isAreaContentPoint(
  content: XYChartExploreState['content'],
): content is {
  type: typeof AREA_VARIANT;
  series: AreaSeriesWithDatapoints;
  datapoint: AreaDatapoint;
} {
  return (
    !!content &&
    content.type === AREA_VARIANT &&
    !!content.series &&
    !!content.datapoint
  );
}

export function isNumericColoringScale(colorScale: XYChartColorScale): boolean {
  return colorScale.domain().every((value) => typeof value === 'number');
}

export const isValidCategoryValue = (value: unknown): value is string =>
  Boolean(value && typeof value === 'string');

export function isDotOrLineSelection(
  point: XYChartSelectionLinearMetadata,
): point is DotOrLineSelection {
  return (
    point.series.type === DOT_VARIANT || point.series.type === LINE_VARIANT
  );
}
